<div class="page-heading"><div><span class="eyebrow">INVENTARIO BASE</span><h2>Catálogo de productos</h2><p>Consulta existencias, costos, categorías y estado operativo.</p></div><a class="btn btn-primary" href="index.php?route=productos/crear"><i class="bi bi-plus-circle me-2"></i>Nuevo producto</a></div>
<section class="panel"><form method="get" class="filter-bar"><input type="hidden" name="route" value="productos"><div class="search-box"><i class="bi bi-search"></i><input name="q" value="<?=htmlspecialchars($filters['search'])?>" placeholder="Buscar por código, nombre o código de barras"></div><select name="categoria" class="form-select"><option value="0">Todas las categorías</option><?php foreach($catalogs['categories'] as $c):?><option value="<?=$c['IdCategoria']?>" <?=$filters['category']==$c['IdCategoria']?'selected':''?>><?=htmlspecialchars($c['Nombre'])?></option><?php endforeach;?></select><select name="estado" class="form-select"><option value="">Todos los estados</option><option value="1" <?=$filters['status']==='1'?'selected':''?>>Activos</option><option value="0" <?=$filters['status']==='0'?'selected':''?>>Inactivos</option></select><button class="btn btn-dark">Filtrar</button><a class="btn btn-light" href="index.php?route=productos">Limpiar</a></form>
<div class="table-responsive"><table class="table modern-table align-middle"><thead><tr><th>Producto</th><th>Categoría</th><th>Proveedor</th><th class="text-end">Stock</th><th class="text-end">Precio</th><th>Estado</th><th></th></tr></thead><tbody><?php foreach($products as $p):?><tr><td><div class="product-cell"><span class="product-badge"><?=htmlspecialchars(substr($p['Nombre'],0,1))?></span><div><strong><?=htmlspecialchars($p['Nombre'])?></strong><small><?=htmlspecialchars($p['Codigo'])?><?=!empty($p['CodigoBarras'])?' · '.htmlspecialchars($p['CodigoBarras']):''?></small></div></div></td><td><?=htmlspecialchars($p['Categoria'])?><small class="d-block text-muted"><?=htmlspecialchars($p['Marca']??'Sin marca')?></small></td><td><?=htmlspecialchars($p['Proveedor']??'No asignado')?></td><td class="text-end"><strong><?=number_format((float)$p['StockActual'],2)?></strong> <?=htmlspecialchars($p['Unidad'])?><small class="d-block <?=((float)$p['StockActual']<=(float)$p['StockMinimo'])?'text-danger':'text-muted'?>">Mín. <?=number_format((float)$p['StockMinimo'],2)?></small></td><td class="text-end">$<?=number_format((float)$p['PrecioVenta'],2)?><small class="d-block text-muted">Costo $<?=number_format((float)$p['PrecioCompra'],2)?></small></td><td><span class="status-badge <?=$p['Estado']?'success':'muted'?>"><?=$p['Estado']?'Activo':'Inactivo'?></span></td><td><div class="table-actions"><a class="btn btn-sm btn-light" href="index.php?route=productos/editar&id=<?=$p['IdProducto']?>"><i class="bi bi-pencil"></i></a><form method="post" action="index.php?route=productos/estado"><input type="hidden" name="csrf_token" value="<?=App\Helpers\Csrf::token()?>"><input type="hidden" name="id" value="<?=$p['IdProducto']?>"><button class="btn btn-sm btn-light" title="Cambiar estado"><i class="bi bi-power"></i></button></form></div></td></tr><?php endforeach;?><?php if(!$products):?><tr><td colspan="7"><div class="empty-state py-5"><i class="bi bi-search"></i><p>No existen productos para los filtros seleccionados.</p></div></td></tr><?php endif;?></tbody></table></div></section>